经典进程的同步问题在多道程序环境下，进程同步问题十分重要，因而吸引了不少学者对它进行研究，由此而产生了一系列经典的进程同步问题，其中较有代表性的是：“生产者—消费者”问题“读者—写者问题”“哲学家进餐问题”等等。
生产者-消费者问题假定在生产者和消费者之间的公用缓冲池中具有n个缓冲池利用信号量mutex实现对诸进程对缓冲池的互斥使用利用信号量empty和full分别表示缓冲池中空缓冲区和满缓冲区的数目只要缓冲池未空，消费者便可从缓冲池中取走一个消息。只要缓冲池未满，生产者便可从缓冲池中送入一个消息。int in =0，out=0;item buffer[n];semaphore mutex =1,empty =n,full=0;void producer()&#123;  do&#123;    producer an item nextp;    ...    wait(empty);    wait(mutex);    buffer[in] =nextp;    in =(in+1)%n;    signal(mutex);    signal(full);  &#125;while(true)&#125;void consumer()&#123;  do&#123;    wait(full);    wait(mutex);    nextc = buffer[out];    out =(out+1)%n;    signal(mutex);    signal(empty);    consumer the item in nextc;    ....  &#125;while(true)&#125;void main()&#123;  cobegin    producer();    consumer();  coend&#125;
定义两个指针：in：生产数据、写入out：消费数据、读取定义缓存池用于存放生产者产出的内容。Item buffer[n] ：缓冲池，能够存放n个数据定义三个信号量Semaphore mutex = 1，empty = n ， full = 0；mutex 相当于开关empty代表可以填入缓冲池的数据数目full代表可以从缓冲池取出的内容数目只要缓冲池未空，消费者便可从缓冲池中取走一个消息。只要缓冲池未满，生产者便可从缓冲池中送入一个消息。void producer()&#123;  do&#123;    producer an item nextp;    ...    wait(empty);    wait(mutex);    buffer[in] =nextp;    in =(in+1)%n;    signal(mutex);    signal(full);  &#125;while(true)&#125;void consumer()&#123;  do&#123;    wait(full);    wait(mutex);    nextc = buffer[out];    out =(out+1)%n;    signal(mutex);    signal(empty);    consumer the item in nextc;    ....  &#125;while(true)&#125;void main（）&#123;	cobegin		Producer(),		Consumer(),	coend&#125;

“哲学家进餐”问题五个哲学家公用一张圆桌，分别坐在周围的五张椅子上圆桌上有五个碗和五只筷子，他们的生活方式是交替地进行思考和进餐。饥饿时哲学家便取其左右最靠近他的筷子，拿到两根筷子时才能进餐。semaphore chopstick[5] =&#123;1,1,1,1,1&#125;;do&#123;...//think...Swait(chopstick[(i+5)%5],chopstick[i]);...//eat...Signal(chopstick[(i+5)%5],chopstick[i]);&#125;while(true)


“读者—写者问题”int RN;//每次只允许至多RN个读者来读semaphore L =RN,mx=1;void Reader()&#123;  do&#123;    Swait(L,1,1);    Swait(mx,1,0);    ...    perform read operation;    ...    Ssignal(L,1);  &#125;while(true);&#125;void Writer()&#123;  do&#123;    Swait(mx,1,1; L,RN,0);    perform write operation;    Signal(mx,1);  &#125;while(true);&#125;void main()&#123;  cobegin    Reader();    Writer();  coend&#125;
